const items = $input.all();

// ── Repair stray literal "\n" / "\r" formatting artifacts ──────────────────
// n8n's form sometimes submits JSON where line breaks come through as the
// literal characters backslash+n instead of a real newline byte. This only
// strips those OUTSIDE of quoted strings, so real \n inside a node's
// jsCode/message stays untouched.
function stripStructuralEscapes(text) {
  let result = '';
  let inString = false;

  for (let i = 0; i < text.length; i++) {
    const char = text[i];

    if (inString) {
      if (char === '\\' && i + 1 < text.length) {
        result += char + text[i + 1];
        i++;
        continue;
      }
      if (char === '"') inString = false;
      result += char;
      continue;
    }

    if (char === '"') {
      inString = true;
      result += char;
      continue;
    }

    if (char === '\\' && (text[i + 1] === 'n' || text[i + 1] === 'r')) {
      i++;
      continue;
    }

    result += char;
  }

  return result;
}

function parseWithRepair(rawText) {
  try {
    return JSON.parse(rawText);
  } catch (e) {
    try {
      return JSON.parse(stripStructuralEscapes(rawText));
    } catch (e2) {
      return null;
    }
  }
}

function isValidWorkflow(parsed) {
  if (!parsed || typeof parsed !== 'object') return false;
  if (!Array.isArray(parsed.nodes) || parsed.nodes.length === 0) return false;
  if (!parsed.connections || typeof parsed.connections !== 'object') return false;

  const nodeNames = new Set();
  const nodeIds   = new Set();

  for (const node of parsed.nodes) {
    if (typeof node.name !== 'string' || node.name.trim() === '') return false;
    if (nodeNames.has(node.name)) return false;
    nodeNames.add(node.name);

    if (typeof node.type !== 'string' || node.type.trim() === '') return false;
    if (typeof node.typeVersion !== 'number') return false;

    // position — n8n uses ARRAY [x, y], NOT object {x, y}
    if (
      !Array.isArray(node.position) ||
      node.position.length < 2 ||
      typeof node.position[0] !== 'number' ||
      typeof node.position[1] !== 'number'
    ) return false;

    if (node.id !== undefined && node.id !== null) {
      if (nodeIds.has(node.id)) return false;
      nodeIds.add(node.id);
    }
  }

  for (const sourceName of Object.keys(parsed.connections)) {
    if (!nodeNames.has(sourceName)) return false;

    const outputGroups = parsed.connections[sourceName];
    if (!outputGroups || typeof outputGroups !== 'object') continue;

    for (const outputType of Object.keys(outputGroups)) {
      const outputBranches = outputGroups[outputType];
      if (!Array.isArray(outputBranches)) continue;

      for (const branch of outputBranches) {
        if (!Array.isArray(branch)) continue;
        for (const conn of branch) {
          if (conn && conn.node && !nodeNames.has(conn.node)) return false;
        }
      }
    }
  }

  return true;
}

for (const item of items) {
  const rawText = item.json["Workflow JSON"];
  const parsed = parseWithRepair(rawText);
  const success = isValidWorkflow(parsed);

  item.json = {
    workflow: success ? parsed : null,
    success
  };
}

return items;
